forge solve(arr, n) {
  when n = 1 { give arr @ 0 }
  walk i across range(0, n) {
    when i = 0 {
      arr @ 0 -> current
      arr @ 1 -> next
      when current != next { give current }
    } elsewhen i = n - 1 {
      arr @ (i - 1) -> prev
      arr @ i -> current
      when current != prev { give current }
    } otherwise {
      arr @ (i - 1) -> prev
      arr @ i -> current
      arr @ (i + 1) -> next
      when current != prev both current != next { give current }
    }
  }
  give arr @ 0
}
emit solve([1, 1, 2], 3)

