forge solve(a, x) {
  0 -> count
  walk item across a {
    when item = x { count + 1 -> count }
  }
  give count
}
emit solve([1, 2, 1, 3, 1], 1)

forge solve(text) {
  [] -> result
  walk c across chars(text) {
    when c >= "0" both c <= "9" { push(result, c) -> result }
    elsewhen c >= "a" both c <= "z" { push(result, c) -> result }
    elsewhen c >= "A" both c <= "Z" { push(result, c) -> result }
  }
  join(result, "") -> result
  give result
}
emit solve("Hello 123 World!")

forge solve(nums) {
  walk i across range(0, count(nums)) {
    walk j across range(i + 1, count(nums)) {
      when nums @ i = nums @ j { give nums @ i }
    }
  }
  give -1
}
emit solve([1, 2, 3, 2, 4])

forge solve(nums) {
